import{_ as s,o as a,c as t,ag as n}from"./chunks/framework.eQLvDOR_.js";const d=JSON.parse(`{"title":"21 Things most claude users have Never Set Up and It's Costing them Hours Every Week","description":"","frontmatter":{"title":"21 Things most claude users have Never Set Up and It's Costing them Hours Every Week","source":"https://x.com/AnatoliKopadze/article/2050225292585607440","clipped_at":"2026-05-06","category":"[Claude_Code_Skills]","tags":["claude-code","prompt-engineering","context-management"],"status":"distilled","compiled":true},"headers":[],"relativePath":"library/Claude_Code_Skills/Claude_Code_Skills - 21 Things most claude users have Never Set Up and It's Costing them Hours Every Week.md","filePath":"library/Claude_Code_Skills/Claude_Code_Skills - 21 Things most claude users have Never Set Up and It's Costing them Hours Every Week.md","lastUpdated":null}`),o={name:"library/Claude_Code_Skills/Claude_Code_Skills - 21 Things most claude users have Never Set Up and It's Costing them Hours Every Week.md"};function i(r,e,p,l,c,h){return a(),t("div",null,[...e[0]||(e[0]=[n(`<p><img src="https://pbs.twimg.com/media/HHPcnD6XIAAqxt0?format=jpg&amp;name=large" alt="图像"></p><p>A single CLAUDE.md file just hit #1 on GitHub Trending with 82,000 stars and 7,800 forks. Most people using Claude have never heard of it. The ones who have don&#39;t know what to actually put in it. That gap is costing people hours every single week. Every time you open a new Claude session, it starts with zero memory. It doesn&#39;t know your name, your work, your preferences, or how you like things done. You spend the first few minutes re-explaining everything, or you don&#39;t, and Claude gives you something that doesn&#39;t fit how you actually work. CLAUDE.md fixes this permanently.</p><h2 id="why-this-matters-for-everyone-not-just-developers" tabindex="-1">Why this matters for everyone - not just developers <a class="header-anchor" href="#why-this-matters-for-everyone-not-just-developers" aria-label="Permalink to &quot;Why this matters for everyone - not just developers&quot;">​</a></h2><p>Most people think CLAUDE.md is a developer tool. It&#39;s not. It&#39;s an instruction file that Claude reads automatically at the start of every session and it works for anyone who uses Claude regularly. Writers use it to lock in their voice and tone so Claude never sounds like someone else. Marketers use it to define their audience so Claude stops writing generic copy. Researchers use it to set how they want information structured. Business owners use it to give Claude the full context of their company so every output fits their reality. Without CLAUDE.md, you are starting from zero every single session. You repeat yourself. You correct the same mistakes. You explain your preferences for the hundredth time. <strong>CLAUDE.md is the first thing you should set up before any serious work with Claude, regardless of what you use it for.</strong></p><h2 id="how-to-create-the-file-takes-2-minutes" tabindex="-1">How to create the file - takes 2 minutes <a class="header-anchor" href="#how-to-create-the-file-takes-2-minutes" aria-label="Permalink to &quot;How to create the file - takes 2 minutes&quot;">​</a></h2><ol><li>Open your project folder and create a new file. Name it exactly &quot;CLAUDE.md&quot; - capital letters, no spaces. It&#39;s just a plain text file with a .md extension.</li><li>Open it in any text editor - Notepad, TextEdit, VS Code, whatever you use. You&#39;ll paste your instructions directly into this file in plain text.</li><li>Copy the instructions from this article that are relevant to you. Paste them in. You don&#39;t need all 21, start with 3 or 4 that solve your biggest frustrations first.</li><li>Save the file. Claude Code reads it automatically every time you open a session in that folder. No setup, no extra steps - it just works from the first message.</li></ol><h2 id="how-claude-talks-to-you" tabindex="-1">How Claude Talks to You <a class="header-anchor" href="#how-claude-talks-to-you" aria-label="Permalink to &quot;How Claude Talks to You&quot;">​</a></h2><p><strong>1 - Kill the filler</strong> Claude&#39;s default is to open every response with &quot;Great question!&quot;, &quot;Of course!&quot;, &quot;Certainly!&quot;, &quot;Absolutely!&quot; - phrases that add nothing and waste your time. When you&#39;re using Claude for hours every day, this friction compounds. One instruction eliminates it permanently. Every response starts directly with the answer. No warmup, no performance of helpfulness - just what you asked for, immediately.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Never open responses with filler phrases like &quot;Great question!&quot;, &quot;Of course!&quot;, &quot;Certainly!&quot;, &quot;Absolutely!&quot;, &quot;Sure!&quot;, or similar warmups.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Start every response with the actual answer.</span></span>
<span class="line"><span>No preamble, no acknowledgment of the question.</span></span>
<span class="line"><span>Just the information.</span></span></code></pre></div><p><strong>2 - Always show options before acting</strong> Claude picks one approach and runs with it by default. You ask it to rewrite a paragraph and it changes the entire tone of the piece. You ask it to restructure a document and it reorganizes things in a way that doesn&#39;t match how you think. Now you&#39;re correcting something you didn&#39;t ask to change. This instruction changes that dynamic entirely. Before any significant task, Claude shows you 2-3 ways it could approach the work. You choose the direction that fits. What follows is what you actually wanted.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>2.Always show options before acting</span></span>
<span class="line"><span>Claude picks one approach and runs with it by default. You ask it to rewrite a paragraph and it changes the entire tone of the piece. You ask it to restructure a document and it reorganizes things in a way that doesn&#39;t match how you think. Now you&#39;re correcting something you didn&#39;t ask to change.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>This instruction changes that dynamic entirely. Before any significant task, Claude shows you 2-3 ways it could approach the work. You choose the direction that fits. What follows is what you actually wanted.</span></span></code></pre></div><p><strong>3 - Be honest when you don&#39;t know</strong> Claude will give you a confident, detailed, completely wrong answer before it admits uncertainty. It fills gaps with plausible-sounding information, dates, statistics, quotes, facts, that feel true but aren&#39;t. You use that information, and the problem shows up later when it matters most. This single instruction changes that behavior. Claude flags uncertainty before answering instead of hiding it inside a confident response. &quot;I&#39;m not sure about this&quot; at the top of a response saves you from building on a foundation that isn&#39;t there.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>If you are uncertain about any fact, statistic, date, quote, or piece of information, say so explicitly before including it.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&quot;I&#39;m not certain about this&quot; is always better than presenting a guess as a fact.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Never fill gaps in your knowledge with plausible-sounding information.</span></span>
<span class="line"><span>When in doubt, say so.</span></span></code></pre></div><p><strong>4 - Match length to what&#39;s actually needed</strong> Ask Claude a simple question and it writes four paragraphs. Ask it to write something complex and it gives you a skeleton that looks complete but isn&#39;t. Neither is useful. Response length should match what the task actually requires, short when the answer is short, detailed when the work demands depth. This instruction calibrates that relationship. No more padding on simple questions, no more shallow output on work that needs real substance.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Match response length to task complexity.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Simple questions get direct, short answers.</span></span>
<span class="line"><span>Complex tasks get full, detailed responses.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Never compress or summarize work that requires real depth.</span></span>
<span class="line"><span>Never pad responses with restatements of the question or closing sentences that repeat what you just said.</span></span></code></pre></div><h2 id="how-claude-behaves" tabindex="-1">How Claude Behaves <a class="header-anchor" href="#how-claude-behaves" aria-label="Permalink to &quot;How Claude Behaves&quot;">​</a></h2><p><strong>5 - Ask before making big changes</strong> You ask Claude to fix one paragraph and it rewrites the entire document. You ask it to shorten something and it removes sections you needed. You ask it to adjust the tone and it changes the structure too. Every time, you lose something you didn&#39;t want to lose, and have to rebuild it from memory or an earlier version. This instruction turns every significant change into a checkpoint. Claude stops, tells you exactly what it&#39;s about to do, and waits for your yes before touching anything. The work that follows is the work you agreed to.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Before making any change that significantly alters content I&#39;ve already created (rewriting sections, removing paragraphs, restructuring the flow, changing tone), stop completely.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Describe exactly what you&#39;re about to change and why.</span></span>
<span class="line"><span>Wait for my confirmation before proceeding.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&quot;I think this would be better&quot; is not permission to change it.</span></span></code></pre></div><p><strong>6 - Stay focused on what was asked</strong> Ask Claude to fix one thing and it will &quot;improve&quot; five others while it&#39;s in there, adjusting your phrasing, reorganizing your structure, rephrasing sentences you were happy with. Sometimes those changes are improvements. Often they&#39;re not. And now you have to sort through everything to find what actually changed. This instruction keeps Claude on task. Fix what was asked. Leave everything else exactly as it is. If something else looks worth addressing, mention it, but don&#39;t touch it without being asked.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Only change what I specifically asked you to change.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Do not rewrite, rephrase, restructure, or &quot;improve&quot; anything I didn&#39;t ask about, even if you think it would be better.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>If you notice something that could be improved elsewhere, mention it at the end of your response.</span></span>
<span class="line"><span>Do not touch it unless I explicitly ask you to.</span></span></code></pre></div><p><strong>7 - Always tell me what you changed</strong> Claude finishes a task and you&#39;re left scanning the output trying to figure out what&#39;s different from what you had before. Which sections changed? Did it cut anything? Did it add something you didn&#39;t ask for? Without a summary, you&#39;re doing a manual diff every single time. This instruction makes Claude close every task with a brief summary: what changed, what stayed the same, and anything that needs your attention. You stay in control of your own work.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>After completing any editing or writing task, always end with a brief summary:</span></span>
<span class="line"><span>- What was changed: [description]</span></span>
<span class="line"><span>- What was left untouched: [if relevant]</span></span>
<span class="line"><span>- What needs my attention: [anything requiring a decision or review]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Keep it short. This is a status update, not a recap of everything you just did.</span></span></code></pre></div><p><strong>8 - Never take actions on my behalf without asking</strong> As AI tools become more connected, to your email, calendar, social accounts, documents, the risk of Claude taking an action you didn&#39;t fully intend grows with every new integration. Sending a message. Posting content. Sharing a document. Scheduling something. These actions have real consequences and they happen fast. This instruction creates a hard wall. No matter what Claude thinks you want, no action with external consequences happens without you explicitly saying yes in that specific moment.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Never send, post, publish, share, or schedule anything on my behalf without my explicit confirmation in the current message.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>This includes:</span></span>
<span class="line"><span>- Emails</span></span>
<span class="line"><span>- Social posts</span></span>
<span class="line"><span>- Calendar invites</span></span>
<span class="line"><span>- Document shares</span></span>
<span class="line"><span>- Any action that affects something outside this conversation</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&quot;You mentioned wanting to do this&quot; is not confirmation.</span></span>
<span class="line"><span>I must say yes in the current message.</span></span></code></pre></div><h2 id="your-context" tabindex="-1">Your Context <a class="header-anchor" href="#your-context" aria-label="Permalink to &quot;Your Context&quot;">​</a></h2><p><strong>9 - Tell Claude who you are and what you know</strong> Claude doesn&#39;t know if you&#39;re an expert or a beginner, a founder or a freelancer, someone who wants technical depth or plain language. Without that context, it guesses, and it&#39;s wrong as often as it&#39;s right. Sometimes it explains things you&#39;ve known for years. Sometimes it skips context you actually need.</p><p>One paragraph about who you are calibrates every response Claude gives you from that point forward. It stops treating you like a stranger and starts talking to you like someone who actually knows you.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>About me:</span></span>
<span class="line"><span>- Name: [Your Name]</span></span>
<span class="line"><span>- Role: [what you do, writer, founder, marketer, researcher, etc.]</span></span>
<span class="line"><span>- Background: [relevant experience or knowledge level]</span></span>
<span class="line"><span>- Strong in: [topics or areas you know well, skip the basics here]</span></span>
<span class="line"><span>- Still learning: [areas where you need more context and explanation]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Adjust the depth of every response to match this background. Never over-explain what I already know. Never skip context I need.</span></span></code></pre></div><p><strong>10 - Give Claude the context of what you&#39;re working on</strong> Every session, Claude starts with no idea what you&#39;re working on, who it&#39;s for, or what actually matters. It gives you generic output because it has no other choice. It doesn&#39;t know your audience. It doesn&#39;t know your goals. It doesn&#39;t know the constraints that shape every decision you make.</p><p>A short context paragraph changes everything. Suggestions stop being generic and start fitting your actual situation. Claude knows who it&#39;s writing for, what tone is right, and what tradeoffs matter to you specifically.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>What I&#39;m working on:</span></span>
<span class="line"><span>- Project: [one sentence description of what this is]</span></span>
<span class="line"><span>- Goal: [what success looks like]</span></span>
<span class="line"><span>- Audience: [who this is for and what they care about]</span></span>
<span class="line"><span>- Tone: [how the writing or output should feel, casual, professional, direct, conversational, etc.]</span></span>
<span class="line"><span>- What to avoid: [anything that doesn&#39;t fit, jargon, certain topics, specific styles]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Apply this context to every task. When something doesn&#39;t fit this picture, flag it before proceeding.</span></span></code></pre></div><p><strong>11 - Lock in your voice and style</strong> Claude has a default writing style. It&#39;s fine. It&#39;s also not yours. It uses certain phrases, structures sentences a particular way, and has a tone that doesn&#39;t match how you actually communicate. Every time you use Claude to write something, you end up editing it back toward your voice anyway. Define your voice once in CLAUDE.md and Claude writes in it from the first draft. Less editing. More output that actually sounds like you.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>My writing style, always match this:</span></span>
<span class="line"><span>- Voice: [e.g. direct, conversational, confident, no-fluff]</span></span>
<span class="line"><span>- Sentence length: [e.g. short and punchy / long and detailed / mixed]</span></span>
<span class="line"><span>- Words I use: [phrases or vocabulary that sound like me]</span></span>
<span class="line"><span>- Words I never use: [words or phrases that don&#39;t fit my style]</span></span>
<span class="line"><span>- Format preference: [e.g. paragraphs only / bullet points / headers / no headers]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>When writing anything on my behalf, match this style exactly. Do not default to your own patterns.</span></span></code></pre></div><h2 id="memory-continuity" tabindex="-1">Memory &amp; Continuity <a class="header-anchor" href="#memory-continuity" aria-label="Permalink to &quot;Memory &amp; Continuity&quot;">​</a></h2><p><strong>12 - Make Claude keep a memory file</strong> Claude forgets everything between sessions. Every conversation starts fresh. But Claude can write files, and files persist. This instruction tells Claude to maintain a MEMORY.md file with every important decision you make together: what was decided, why, and what alternatives were considered and rejected. At the start of each session, Claude reads that file. Suddenly it knows why you made the choices you made two months ago. It stops re-suggesting things you already tried. It builds on your decisions instead of contradicting them.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Maintain a file called MEMORY.md. After any significant decision, about direction, format, content, approach, or strategy, add an entry:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## [Date], [Decision]</span></span>
<span class="line"><span>**What was decided:** [the choice made]</span></span>
<span class="line"><span>**Why:** [the reasoning]</span></span>
<span class="line"><span>**What was rejected:** [alternatives considered and why they were ruled out]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Read MEMORY.md at the start of every session before doing anything. Never contradict a logged decision without flagging it first.</span></span></code></pre></div><p><strong>13 - End-of-session summary, never lose progress</strong> You close the session. You come back two days later. You spend 15 minutes reading old messages trying to remember where you were, what you finished, and what you were in the middle of. This is a completely avoidable waste that happens to almost everyone who uses Claude regularly.</p><p>This instruction makes Claude write a session summary to MEMORY.md before you wrap up. Next session opens with full context. You pick up exactly where you left off without reconstructing anything from scratch.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>When I say &quot;session end&quot;, &quot;wrapping up&quot;, or &quot;let&#39;s stop here&quot;, write a session summary to MEMORY.md:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## Session Summary, [Date]</span></span>
<span class="line"><span>**Worked on:** [what we focused on]</span></span>
<span class="line"><span>**Completed:** [what&#39;s finished]</span></span>
<span class="line"><span>**In progress:** [what&#39;s started but not done]</span></span>
<span class="line"><span>**Decisions made:** [key choices from this session]</span></span>
<span class="line"><span>**Next session:** [what to pick up first and any important context to carry forward]</span></span></code></pre></div><p><strong>14 - Log what didn&#39;t work, stop solving the same problem twice</strong> You try a prompt approach for a piece of content. It takes four attempts to get something usable. Three weeks later you&#39;re back with a similar task and Claude starts over with the same bad suggestions. The same trial and error, the same wasted time, from the beginning.</p><p>An error log breaks that loop. Every approach that failed gets documented, what you tried, why it didn&#39;t work, what finally did. Next time Claude checks the log first and skips straight to what&#39;s known to work.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Maintain a file called ERRORS.md. When an approach takes more than 2 attempts to work, log it:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## [Task type or description]</span></span>
<span class="line"><span>**What didn&#39;t work:** [approaches that failed and why]</span></span>
<span class="line"><span>**What worked:** [the approach that finally succeeded]</span></span>
<span class="line"><span>**Note for next time:** [anything worth remembering for similar tasks]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Check ERRORS.md before suggesting approaches to tasks similar to logged ones. If a task matches a logged failure, say so and skip to what worked.</span></span></code></pre></div><p><strong>15 - Give Claude a list of facts that never change</strong> Every project has permanent facts: constraints that come from past decisions, rules that exist for important reasons, things that are always true about your work regardless of the specific task. Without this instruction, Claude doesn&#39;t know these facts exist, and will casually suggest things that contradict them, undo work you did for a reason, or require you to stop and explain the same context for the hundredth time.</p><p>This block gives Claude a permanent foundation that applies to every session, every task, every output. You stop repeating yourself. Claude operates inside your actual reality instead of a generic version of it.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>These facts are always true. Apply them to every session and every task without exception:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>- [Permanent fact #1, e.g. &quot;My audience does not have a technical background&quot;]</span></span>
<span class="line"><span>- [Permanent fact #2, e.g. &quot;All content must be appropriate for a professional context&quot;]</span></span>
<span class="line"><span>- [Permanent fact #3, e.g. &quot;We never make claims without a source&quot;]</span></span>
<span class="line"><span>- [Permanent fact #4, e.g. &quot;The brand voice is always warm, never corporate&quot;]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>If any task conflicts with one of these, flag it before proceeding. Do not work around a constraint without telling me.</span></span></code></pre></div><h2 id="for-developers" tabindex="-1">For Developers <a class="header-anchor" href="#for-developers" aria-label="Permalink to &quot;For Developers&quot;">​</a></h2><p>The instructions below are specifically for people using Claude Code to write, review, or manage code. If that&#39;s not you, everything above is enough. If it is, these six rules are the difference between Claude being a useful coding assistant and a loose cannon in your codebase.</p><p><strong>16 - Stay in scope, touch nothing you weren&#39;t asked about</strong> Ask Claude to fix one bug and it will refactor three files, rename your variables, reorganize your imports, and &quot;improve&quot; code you&#39;ve been working with for months, all without asking. Some of those changes break things. Some introduce subtle differences that take days to track down.</p><p>This is one of the most important rules for anyone using Claude Code. Scope control is the difference between a precise tool and a loose cannon in your codebase.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Only modify files, functions, and lines of code directly and specifically related to the current task.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Do not refactor, rename, reorganize, reformat, or &quot;improve&quot; anything I did not explicitly ask you to change.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>If you notice something worth fixing elsewhere, mention it in a note.</span></span>
<span class="line"><span>Do not touch it. Ever.</span></span></code></pre></div><p><strong>17 - Confirm before anything destructive</strong> Claude Code runs in your terminal with access to your file system. It will delete files, overwrite functions, and drop database tables without hesitation, because you told it to, even if you didn&#39;t fully realize what you were telling it. One misread instruction and hours of work are gone with no undo.</p><p>This rule turns every destructive action into a checkpoint. Claude stops, shows you exactly what will be affected, and waits for your explicit yes before touching anything.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Before deleting any file, overwriting existing code, dropping database records, removing dependencies, or making any change that cannot be trivially undone, stop completely. List exactly what will be affected. Ask for explicit confirmation. Only proceed after I say yes in the current message.</span></span></code></pre></div><p><strong>18 - Hard stops, actions that never happen without explicit permission</strong> Deploying to production. Running migrations on a live database. Sending API calls to external services. These are not &quot;be careful&quot; situations, they are full stops that require you to be consciously in the room and deliberately saying yes. This rule creates a permanent wall around those actions.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>The following actions require explicit in-session confirmation before executing, no exceptions:</span></span>
<span class="line"><span>- Deploying or pushing to any environment (staging, production, etc.)</span></span>
<span class="line"><span>- Running migrations or schema changes on any database</span></span>
<span class="line"><span>- Sending any email, message, or external API call</span></span>
<span class="line"><span>- Executing any command with irreversible external side effects</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&quot;You mentioned this earlier&quot; is not confirmation. I must say yes in the current message.</span></span></code></pre></div><p><strong>19 - Lock your tech stack</strong> Without a defined stack, Claude will suggest whatever framework it considers most popular, whatever library it&#39;s seen most often, and whatever package manager it defaults to. Sometimes fine. Often not what you use, not what your team knows, and not compatible with what you&#39;ve already built.</p><p>Define the stack once and Claude stops suggesting things you don&#39;t want. Everything it writes fits the system you&#39;re actually building.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Tech stack, always use these, never suggest alternatives unless I ask:</span></span>
<span class="line"><span>- Language(s): [list]</span></span>
<span class="line"><span>- Framework(s): [list]</span></span>
<span class="line"><span>- Package manager: [npm / yarn / pip / cargo / etc.]</span></span>
<span class="line"><span>- Database: [list]</span></span>
<span class="line"><span>- Testing: [your testing framework]</span></span>
<span class="line"><span>- Linting / formatting: [your tools]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>If something in the stack seems like the wrong tool, flag it, but use it anyway unless I say otherwise.</span></span></code></pre></div><p><strong>20.Always show exactly what changed</strong> Claude finishes a task and you&#39;re left scanning the output trying to figure out what&#39;s different. Which files changed? Did it touch anything else? Did it leave something unfinished? Without a file-level summary you&#39;re doing a manual diff every single time you ask Claude to do anything.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>After completing any coding task, always end with:</span></span>
<span class="line"><span>- Files changed: [list every file touched]</span></span>
<span class="line"><span>- What was modified: [one line per file]</span></span>
<span class="line"><span>- Files intentionally not touched: [if relevant]</span></span>
<span class="line"><span>- Follow-up needed: [anything requiring my attention or a decision]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Keep it short. This is a status update, not a recap.</span></span></code></pre></div><p><strong>21 - The 4 rules that made Andrej Karpathy&#39;s CLAUDE.md go viral</strong> Andrej Karpathy, former Director of AI at Tesla, founding member of OpenAI, identified 4 specific behaviors that make Claude Code fail at coding tasks. A developer distilled them into 4 instructions in a single CLAUDE.md file. That file hit #1 on GitHub Trending and improved coding accuracy from 65% to 94%.</p><p>These are the 4 rules. They&#39;re worth adding to every developer&#39;s CLAUDE.md regardless of what else is in there.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. Ask, don&#39;t assume. If something is unclear or underspecified, ask before writing a single line. Never make silent assumptions about intent, architecture, or requirements.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. Simplest solution first. Always implement the simplest thing that could work. Do not add abstractions, layers, or flexibility that weren&#39;t explicitly requested.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. Don&#39;t touch unrelated code. If a file or function is not directly part of the current task, do not modify it, even if you think it could be improved.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4. Flag uncertainty explicitly. If you are not confident about an approach, a library&#39;s behavior, or a technical detail, say so before proceeding. Confidence without certainty causes more damage than admitting a gap.</span></span></code></pre></div><p>CLAUDE.md is not just a developer tool. It&#39;s a permanent instruction file that anyone who uses Claude seriously should set up before their first real session. Instructions 1-4 fix how Claude communicates. Instructions 5-8 stop it from changing things you didn&#39;t authorize. Instructions 9-11 give it the context to produce output that fits your actual work. Instructions 12-15 give it the closest thing to real memory that currently exists. Instructions 16-21 are for developers who want Claude Code to behave like a precise tool instead of an unpredictable one. Create the file. Paste in 3 instructions. Add more as you go.</p><p>Follow <a href="https://x.com/@AnatoliKopadze" target="_blank" rel="noreferrer">@AnatoliKopadze</a> for more systems that actually change how you work with AI.</p>`,65)])])}const g=s(o,[["render",i]]);export{d as __pageData,g as default};
